void KNNWrapper::queryKNN(const std::vector<float>& query_vec, std::vector<int>& result_ids, int k) {
    if (!is_built) {
        std::cerr << "Error: Graph not built." << std::endl;
        return;
    }

    if (query_vec.size() != dimensions) {
        std::cerr << "Error: Query dimension mismatch." << std::endl;
        return;
    }

    // Копирование запроса на GPU
    float* d_query;
    cudaMalloc(&d_query, dimensions * sizeof(float));
    cudaMemcpy(d_query, query_vec.data(), dimensions * sizeof(float), cudaMemcpyHostToDevice);

    // В реальном проекте здесь запускается ядро поиска по графу (HNSW traversal)
    // Для примера: просто возвращаем первые k индексов (заглушка)
    result_ids.clear();
    for (int i = 0; i < k && i < num_points; ++i) {
        result_ids.push_back(i);
    }

    cudaFree(d_query);

    if (verbose_queries) {
        std::cout << "[QUERY] Found " << result_ids.size() << " neighbors." << std::endl;
    }
}

void KNNWrapper::queryDetailed(const std::vector<float>& query_vec, std::vector<int>& result_ids, std::vector<float>& result_dists, int k) {
    if (!is_built) {
        std::cerr << "Error: Graph not built." << std::endl;
        return;
    }

    if (query_vec.size() != dimensions) {
        std::cerr << "Error: Query dimension mismatch." << std::endl;
        return;
    }

    // Копирование запроса
    float* d_query;
    cudaMalloc(&d_query, dimensions * sizeof(float));
    cudaMemcpy(d_query, query_vec.data(), dimensions * sizeof(float), cudaMemcpyHostToDevice);

    // В реальном проекте здесь запускается ядро поиска с вычислением точных расстояний
    // Для примера: заполняем случайными значениями
    result_ids.clear();
    result_dists.clear();

    for (int i = 0; i < k && i < num_points; ++i) {
        result_ids.push_back(i);
        result_dists.push_back(i * 0.1f); // Заглушка расстояния
    }

    cudaFree(d_query);

    if (verbose_queries) {
        std::cout << "[QUERY DETAIL] Results: ";
        for (int i = 0; i < result_ids.size(); ++i) {
            std::cout << "(" << result_ids[i] << ", " << result_dists[i] << ") ";
        }
        std::cout << std::endl;
    }
}

