### 2. Реализация скрипта сборки (`scripts/build.js`)

Этот скрипт использует только стандартные модули Node.js (`fs`, `path`, `glob`), чтобы не зависеть от тяжелых фреймворков, но при этом быть модульным.

```javascript
import { promises as fs } from 'fs';
import { join, dirname, resolve } from 'path';
import { fileURLToPath } from 'url';
import { glob } from 'glob';

// Получаем путь к текущему файлу для работы с относительными путями
const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const ROOT_DIR = resolve(__dirname, '..');

// Конфигурация путей
const PATHS = {
  src: join(ROOT_DIR, 'src'),
  public: join(ROOT_DIR, 'public'),
  build: join(ROOT_DIR, 'build'),
};

/**
 * Утилита для безопасного создания директорий
 */
async function ensureDir(dirPath) {
  try {
    await fs.mkdir(dirPath, { recursive: true });
  } catch (err) {
    if (err.code !== 'EEXIST') throw err;
  }
}

/**
 * Шаг 1: Генерация файлов парсеров
 * Читает данные из config.json и применяет их к шаблону
 */
async function generateParsers() {
  console.log('🔧 Шаг 1: Генерация файлов парсеров...');

  const configPath = join(PATHS.src, 'data', 'config.json');
  const templatePath = join(PATHS.src, 'templates', 'parser.tpl');

  const configData = JSON.parse(await fs.readFile(configPath, 'utf-8'));
  const templateContent = await fs.readFile(templatePath, 'utf-8');

  // Простая замена переменных в шаблоне (можно заменить на Handlebars/EJS для сложных случаев)
  const generatedParser = templateContent
    .replace('{{VERSION}}', configData.version)
    .replace('{{ENDPOINTS}}', JSON.stringify(configData.endpoints, null, 2))
    .replace('{{AUTHOR}}', configData.author);

  const outputPath = join(PATHS.build, 'generated', 'parser.js');
  await ensureDir(dirname(outputPath));
  await fs.writeFile(outputPath, generatedParser, 'utf-8');

  console.log(`✅ Парсер сгенерирован: ${outputPath}`);
  return outputPath;
}

/**
 * Шаг 2: Генерация статических шаблонов
 */
async function generateTemplates() {
  console.log('🔧 Шаг 2: Генерация шаблонов...');

  const templates = await glob(join(PATHS.src, 'templates', '*.tpl'));

  for (const tplPath of templates) {
    if (tplPath.includes('parser.tpl')) continue; // Пропускаем уже обработанный

    const content = await fs.readFile(tplPath, 'utf-8');
    const fileName = tplPath.split('/').pop().replace('.tpl', '.html');
    const outputPath = join(PATHS.build, 'generated', fileName);

    await ensureDir(dirname(outputPath));
    await fs.writeFile(outputPath, content, 'utf-8');
    console.log(`✅ Шаблон сгенерирован: ${outputPath}`);
  }
}

/**
 * Шаг 3: Сборка и организация публичного каталога
 * Копирует сгенерированные файлы в public с нужной структурой
 */
async function buildPublicCatalog() {
  console.log('🏗️  Шаг 3: Сборка публичного каталога...');

  // Очистка публичной директории (опционально)
  // await fs.rm(PATHS.public, { recursive: true, force: true });
  await ensureDir(PATHS.public);

  // 1. Создаем подкаталог для JS
  const jsDir = join(PATHS.public, 'js');
  await ensureDir(jsDir);

  // 2. Создаем подкаталог для CSS (имитация)
  const cssDir = join(PATHS.public, 'css');
  await ensureDir(cssDir);
  await fs.writeFile(join(cssDir, 'main.css'), 'body { margin: 0; }', 'utf-8');

  // 3. Создаем подкаталог для изображений
  const imgDir = join(PATHS.public, 'images');
  await ensureDir(imgDir);
  // Создаем заглушку изображения
  await fs.writeFile(join(imgDir, 'logo.png'), 'FAKE_IMAGE_DATA', 'utf-8');

  // 4. Копируем сгенерированные файлы
  const generatedFiles = await glob(join(PATHS.build, 'generated', '**', '*'));

  for (const file of generatedFiles) {
    const relativePath = file.replace(join(PATHS.build, 'generated'), '');
    const destPath = join(PATHS.public, relativePath);

    await ensureDir(dirname(destPath));
    await fs.copyFile(file, destPath);
    console.log(`📦 Копирование: ${relativePath}`);
  }

  // 5. Генерация index.html (финальная сборка)
  const indexContent = `
    <!DOCTYPE html>
    <html lang="ru">
    <head>
      <meta charset="UTF-8">
      <title>Собранный проект</title>
      <link rel="stylesheet" href="/css/main.css">
    </head>
    <body>
      <h1>Привет, мир!</h1>
      <img src="/images/logo.png" alt="Logo">
      <script src="/js/parser.js"></script>
    </body>
    </html>
  `;

  await fs.writeFile(join(PATHS.public, 'index.html'), indexContent, 'utf-8');
  console.log('✅ Публичный каталог успешно собран.');
}

/**
 * Основной процесс сборки
 */
async function runBuild() {
  console.log('🚀 Запуск системы сборки...\n');

  try {
    await generateParsers();
    await generateTemplates();
    await buildPublicCatalog();

    console.log('\n✨ Сборка завершена успешно!');
    console.log(`📂 Выходные файлы находятся в: ${PATHS.public}`);
  } catch (error) {
    console.error('❌ Ошибка при сборке:', error.message);
    process.exit(1);
  }
}

runBuild();
```

